<?php require_once 'config/db.php'; $msg=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $name=trim($_POST['name']); $email=trim($_POST['email']); $password=password_hash($_POST['password'], PASSWORD_DEFAULT); try{$stmt=$pdo->prepare('INSERT INTO users(name,email,password,role) VALUES(?,?,?,"user")'); $stmt->execute([$name,$email,$password]); $msg='Account created. You can now login.';}catch(Exception $e){$msg='Email already exists.';}} ?><!DOCTYPE html><html><head><title>Register</title><link rel="stylesheet" href="assets/style.css"></head><body><div class="login-wrap"><form class="login-box" method="post"><h1>Register</h1><?php if($msg): ?><div class="alert alert-success"><?php echo $msg; ?></div><?php endif; ?><label>Name</label><input name="name" required><label>Email</label><input name="email" type="email" required><label>Password</label><input name="password" type="password" required minlength="6"><button class="btn btn-primary" style="width:100%;margin-top:18px">Create Account</button><p><a href="login.php">Back to login</a></p></form></div></body></html>